module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    localparam [1:0] RESET  = 2'd0,
                     CLEAR  = 2'd1,
                     UPDATE = 2'd2,
                     IDLE   = 2'd3;

    localparam integer SUM_W = COUNT_WIDTH + 1;

    logic [1:0] state;
    logic [1:0] next_state;

    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    logic [SUM_W-1:0] add_full;
    logic             clear_enable_priority;
    logic             priority_clear_wins;

    // Named SSOT output-rule observables used as live RTL signals.
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    assign add_full = {1'b0, count_q} + {{(SUM_W-STEP_WIDTH){1'b0}}, step};

    assign clear_enable_priority = clear & enable;
    assign priority_clear_wins   = clear | clear_enable_priority;

    always @(*) begin
        next_state = state;
        case (state)
            RESET: begin
                if (rst_n == 1'b1) begin
                    next_state = IDLE;
                end else begin
                    next_state = RESET;
                end
            end
            IDLE: begin
                if (priority_clear_wins == 1'b1) begin
                    next_state = CLEAR;
                end else if (enable == 1'b1) begin
                    next_state = UPDATE;
                end else begin
                    next_state = IDLE;
                end
            end
            UPDATE: begin
                next_state = IDLE;
            end
            CLEAR: begin
                next_state = IDLE;
            end
            default: begin
                next_state = RESET;
            end
        endcase
    end

    // latency=1 contract: commit clear/update/idle effects on the sampling edge.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state     <= RESET;
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else begin
            state <= next_state;

            if (priority_clear_wins == 1'b1) begin
                count_q   <= {COUNT_WIDTH{1'b0}};
                wrapped_q <= 1'b0;
                valid_q   <= 1'b0;
            end else if (enable == 1'b1) begin
                count_q   <= add_full[COUNT_WIDTH-1:0];
                wrapped_q <= add_full[COUNT_WIDTH];
                valid_q   <= 1'b1;
            end else begin
                count_q   <= count_q;
                wrapped_q <= 1'b0;
                valid_q   <= 1'b0;
            end
        end
    end

    assign out_count   = count_q;
    assign out_wrapped = wrapped_q;
    assign out_valid   = valid_q;

    assign count   = out_count;
    assign wrapped = out_wrapped;
    assign valid   = out_valid;

endmodule

